const fs = require('fs');
const path = require('path');

function shuffle(a) { const arr = [...a]; for (let i = arr.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [arr[i], arr[j]] = [arr[j], arr[i]]; } return arr; }

let id = 100000;
function nid() { return id++; }

// Compact format: [question, correct, wrong1, wrong2, wrong3, explanation]
function expand(entries) {
  return entries.map(([q, c, w1, w2, w3, e]) => {
    const opts = shuffle([c, w1, w2, w3]);
    return { id: nid(), question: q, options: opts, correct: opts.indexOf(c), explanation: e || '' };
  });
}

function fill(arr, n) {
  const result = [];
  let i = 0;
  while (result.length < n) {
    const item = { ...arr[i % arr.length], id: nid() };
    result.push(item);
    i++;
  }
  return result;
}

